import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import reportWebVitals from './reportWebVitals';
import Homepage from './landing_page/home/Homepage';
import '@fortawesome/fontawesome-free/css/all.min.css';
import {
  BrowserRouter as Router,
  Routes,
  Route,
  BrowserRouter
} from "react-router-dom";
import Signup from './landing_page/signup/Signup';
// import About from './landing_page/About';
import Product from './landing_page/Product';
import Pricing from './landing_page/Pricing';
import SupportPage from './landing_page/Support';

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <BrowserRouter>
    <Routes>
      <Route path="/" element={<Homepage />} />
       <Route path="/Signup" element={<Signup/>} />
        <Route path="/about" element={<Signup/>} />
        <Route path="/product" element={<Signup/>} />
         <Route path="/pricing" element={<Signup/>} />
 <Route path="/support" element={<Signup/>} />

    </Routes>
  </BrowserRouter>
);
